import{_ as t,o,c as p,aj as a}from"./chunks/framework.DNJ2HNkG.js";const _=JSON.parse('{"title":"笔记本显卡43错误","description":"","frontmatter":{"title":"笔记本显卡43错误","date":"2016-07-25T13:13:33.000Z","category":"Windows","tags":["驱动"]},"headers":[],"relativePath":"posts/笔记本显卡43错误.md","filePath":"posts/笔记本显卡43错误.md","lastUpdated":1783047625000}'),s={name:"posts/笔记本显卡43错误.md"};function c(n,e,i,r,E,l){return o(),p("div",null,[...e[0]||(e[0]=[a('<p>最近突然发现我的Dell XPS 9530的N卡出问题了，在<code>设备管理器</code>中看到显卡有，但有个三角形警告标志，打开看到提示<code>由于该设备有问题，Windows已将其停止。（代码43）</code>，试了下<code>Diable 3</code>发现有卡帧，说明独显没工作，打开控制面板中的NV控制面板，启动报错。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E7%AC%94%E8%AE%B0%E6%9C%AC%E6%98%BE%E5%8D%A143%E9%94%99%E8%AF%AF/1591025121225.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E7%AC%94%E8%AE%B0%E6%9C%AC%E6%98%BE%E5%8D%A143%E9%94%99%E8%AF%AF/1591025121188.png" alt=""></p><p>右键<code>禁止</code>再<code>启用</code>也不行，显卡之前一直是正常的。下载最新NV官方驱动安装，不行，重装Dell官方驱动不行，用DDU彻底卸载NV驱动再装，还是不行！</p><p>既然重装驱动不行，那我重装系统吧！</p><p>重装Win10，不行，换Win7，不行，换Win8，行了？装完后在设备管理器里面显示正常，但重启系统后还是不行，依旧是<code>代码43</code>。</p><p>Google了一下，发现很多人都遇到了<code>Code 43</code> error这个错，有的说用DDU卸载了驱动后再装可以用，有的说在设备管理中手动安装驱动可以用，甚至有人专门在<code>Youtube</code>上录制了视频，但我测试后都发现不行。有的说是GPU挂了，换主板吧，看了下，TB价1K2左右，不算贵，但我这个真的是硬件故障么？不大可能吧~~</p><p>拨打Dell官方客服电话，问了几句，直接说是我硬件问题，然后我的机器过保了，交钱到维修点维修。好吧，Dell的售后越做越差了，曾经我的Dell XPS L502X，就是被Dell售后把好的机器弄成了问题机器！</p><p>难道是BIOS问题？显卡硬件识别的原因？将A09降级到了A08，问题依旧，再升级回A09，还是不行。</p><p>本来准备将就用的，无非不用独显，反正游戏玩的少，于是顺便装了Win7，Win10的兼容性还是差了点，禁用了独显正常开发木问题。</p><p>晚上突然想起一种可能性，网上很多出现这种问题的显卡，都是老显卡，然后装了Win10以后，就出问题了！</p><p>有可能是Win10系统自带的驱动向NV显卡的寄存器写入了某些配置，但这些配置对老显卡适配有问题，导致显卡驱动异常！说干就干，清寄存器的方法很简单，断电即可，因为XPS 9530是内置电池，拆开后盖，将电池的接线拔下，然后按电源开关开机几次，再将电池接上，开机，O了。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E7%AC%94%E8%AE%B0%E6%9C%AC%E6%98%BE%E5%8D%A143%E9%94%99%E8%AF%AF/1591025121226.png" alt=""></p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E7%AC%94%E8%AE%B0%E6%9C%AC%E6%98%BE%E5%8D%A143%E9%94%99%E8%AF%AF/1591025121224.jpg" alt=""></p><p>果然，坑爹的Win10！新系统对老硬件的兼容果然问题多多，还很隐蔽！</p><p>在主板和显卡上，其实有很多寄存器是可写的，这些寄存器有些事RAM有些是ROM，这些寄存器的配置都是主板和显卡的工作参数，如果写入了特殊数据，呵呵哒~~</p><p>写这些寄存器的接口官方基本上不开放的，这些接口只在厂商研发时候，以及生产厂商出厂检测时候用，外面很难找到相关资料，所以，想要研究，逆向驱动自己挖掘吧！</p><p>但这个安全方向非常V587，CIH病毒，BIOS木马，都只是前奏，下一步应该就是这个方面了~~</p>',17)])])}const A=t(s,[["render",c]]);export{_ as __pageData,A as default};
